import os
import io
import pandas as pd
import boto3

source = "datagov/budget-2019-budget-recommendations-positions-and-salaries/files/rows.txt"
bucket = "lakeqa-yc4103-datalake"
local_path = source if os.path.exists(source) else "/tmp/k123_data_cache/" + source

if os.path.exists(local_path):
    df = pd.read_csv(local_path, sep=",", engine="c", low_memory=False)
else:
    obj = boto3.client("s3").get_object(Bucket=bucket, Key=source)
    df = pd.read_csv(io.BytesIO(obj["Body"].read()), sep=",", engine="c", low_memory=False)
node_4_answer = {'50': 42342535.0, '57': 1293487079.0, '85': 144020555.0, '99': 0.0}
node_5_answer = {'50': 42996687.0, '57': 1308621421.0, '85': 159362510.0, '99': 0.0}
node_6_answer = {'50': 43046519.0, '57': 1277019448.0, '85': 158941618.0, '99': 0.0}

def active_codes(d):
    out = set()
    for k, v in d.items():
        code = int(float(k))
        if float(v) > 0:
            out.add(code)
    return out

codes = active_codes(node_4_answer) & active_codes(node_5_answer) & active_codes(node_6_answer)

df_codes = pd.to_numeric(df["DEPARTMENT CODE"], errors="coerce")
df_amt = pd.to_numeric(df["TOTAL BUDGETED AMOUNT"], errors="coerce")
df2 = pd.DataFrame({"code": df_codes, "amt": df_amt}).dropna(subset=["code"])
df2["code"] = df2["code"].astype(int)
filtered = df2[df2["code"].isin(codes)]
totals = filtered.groupby("code", dropna=True)["amt"].sum().to_dict()
answer = {str(code): float(totals.get(code, 0.0)) for code in sorted(codes)}

